var e=(e,t,n,r,i,a)=>{let o=Number(e)||0,s=Number(t)||1,c=Number(n)||1,l=Number(r)||1,u=Number(i)||1,d=u+(Number(a)||0),f=o/s*(u/d),p=f/c,m=p/l;return{mrp:o,retailerCost:f,dbCost:p,ssCost:m,retailerMarginPercent:o>0?(o-f)/o*100:0,dbMarginPercent:f>0?(f-p)/f*100:0,ssMarginPercent:p>0?(p-m)/p*100:0,formulaStrip:`₹${o.toFixed(2)} MRP → ÷ ${s.toFixed(2)} × ${u}/${d} = ₹${f.toFixed(2)} → ÷ ${c.toFixed(2)} = ₹${p.toFixed(2)} DB → ÷ ${l.toFixed(2)} = ₹${m.toFixed(2)} SS`}};export{e as t};